@startuml
!theme plain

class "PubSubEvent`1" {
  <<interface>>
}

class "LoginArgs" {
  <<class>>
  LoginArgs(user:IUser, phase:LoginPhase)
}

class "UserPreLoginEvent" {
  <<class>>
}

class "LoginPhase" {
  <<enumeration>>
  Request, Response, Success,
}

class "IUser" {
  <<interface>>
}

UserPreLoginEvent --|> PubSubEvent`1 : <LoginArgs>
LoginArgs --> LoginPhase : Phase
LoginArgs --> IUser : User

@enduml
